}}];

// Code in JavaScript2 — text/voice path
// UPDATED: reads recent execution_result from Supabase via HTTP

const trigger = $('Telegram Trigger').first().json;

const from =
  trigger.edited_message?.from ||
  trigger.message?.from ||
  null;

const userId = from?.id || null;

if (!userId) {
  throw new Error('Cannot identify user — Telegram from.id missing');
}

const username = from
  ? (`${from.first_name || ''} ${from.last_name || ''}`).trim() || from.username || 'Unknown'
  : 'Unknown';

const isReset = ['try again','start over','cancel','reset','restart','abort']
  .some(p => ($json.text || '').toLowerCase().includes(p));

// ── Read recent execution result from Supabase ──
// We call the Supabase REST API directly since we can't add async nodes here.
// Fetch the most recently executed proposal for this user.
let lastExecutionResult = null;
try {
  const SUPABASE_URL = 'https://puoymncyegcmewibjeyz.supabase.co';
  const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InB1b3ltbmN5ZWdjbWV3aWJqZXl6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NjU2NTQxMiwiZXhwIjoyMDgyMTQxNDEyfQ.vgkXUijbN1ihjfvI8voMUIxhcPmp-vROULBQ4R2fofI';
  const TEN_MINUTES  = 10 * 60 * 1000;

  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/crm_action_proposals` +
    `?user_id=eq.${userId}&status=eq.executed` +
    `&execution_result=not.is.null` +
    `&order=executed_at.desc&limit=1`,
    { headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
    }}
  );

  const rows = await resp.json();
  if (rows.length > 0) {
    const row = rows[0];
    const executedAt = new Date(row.executed_at).getTime();
    if (!isNaN(executedAt) && (Date.now() - executedAt) < TEN_MINUTES) {
      lastExecutionResult = row.execution_result;
    }
  }
} catch (e) {
  // Swallow — last_execution_result will be null, agent proceeds normally
}

return [{ json: {
  user_message:           $json.text || '',
  user_id:                userId,
  username:               username,
  structured_contact_data: null,
  previous_proposal:      null,
  last_execution_result:  isReset ? null : lastExecutionResult,
  is_reset:               isReset
}}];
